import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import {
  NotificationHistoryService,
  resetNotificationLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { EmailTransport, EmailMessage } from '../../src/adapters/email.adapter.js';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { SmsTransport, SmsMessage } from '../../src/adapters/sms.adapter.js';
import { WebhookAdapter } from '../../src/adapters/webhook.adapter.js';
import type { WebhookTransport, WebhookRequestBody } from '../../src/adapters/webhook.adapter.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { Database } from '../../src/utils/database.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

/**
 * Integration tests for the full notification pipeline:
 * EventBus → NotificationService → preferences check → adapter dispatch → history logging
 *
 * These tests wire up real instances of all components (services, repositories, adapters)
 * with mock transports for external delivery (email/SMS/webhook APIs).
 */

// Mock transports that record what was sent
function createMockEmailTransport() {
  const sent: EmailMessage[] = [];
  const transport: EmailTransport = {
    async sendMail(message: EmailMessage) {
      sent.push(message);
      return { messageId: `email-${sent.length}` };
    },
  };
  return { transport, sent };
}

function createMockSmsTransport() {
  const sent: SmsMessage[] = [];
  const transport: SmsTransport = {
    async sendSms(message: SmsMessage) {
      sent.push(message);
      return { messageId: `sms-${sent.length}` };
    },
  };
  return { transport, sent };
}

function createMockWebhookTransport() {
  const sent: { url: string; body: WebhookRequestBody; headers: Record<string, string> }[] = [];
  const transport: WebhookTransport = {
    async post(url: string, body: WebhookRequestBody, headers: Record<string, string>) {
      sent.push({ url, body, headers });
      return { statusCode: 200 };
    },
  };
  return { transport, sent };
}

// Helpers to build common test events
function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
    ...overrides,
  };
}

describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let historyService: NotificationHistoryService;
  let preferencesRepo: PreferencesRepository;
  let logRepo: NotificationLogRepository;

  // Mock transports
  let emailTransport: ReturnType<typeof createMockEmailTransport>;
  let smsTransport: ReturnType<typeof createMockSmsTransport>;
  let webhookTransport: ReturnType<typeof createMockWebhookTransport>;

  beforeEach(() => {
    // Reset ID counters
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();

    // Fresh database and event bus
    db = new Database();
    eventBus = new EventBus();

    // Repositories
    preferencesRepo = new PreferencesRepository(db);
    logRepo = new NotificationLogRepository(db);

    // Services
    preferencesService = new PreferencesService(preferencesRepo);
    historyService = new NotificationHistoryService(logRepo);
    notificationService = new NotificationService(eventBus);
    notificationService.setPreferencesService(preferencesService);
    notificationService.setHistoryService(historyService);

    // Mock transports
    emailTransport = createMockEmailTransport();
    smsTransport = createMockSmsTransport();
    webhookTransport = createMockWebhookTransport();

    // Register adapters
    notificationService.registerAdapter(
      new EmailAdapter({
        from: 'noreply@shop.test',
        replyTo: 'support@shop.test',
        transport: emailTransport.transport,
      }),
    );
    notificationService.registerAdapter(
      new SmsAdapter({
        from: '+15550001111',
        transport: smsTransport.transport,
      }),
    );
    notificationService.registerAdapter(
      new WebhookAdapter({
        url: 'https://hooks.test/notifications',
        secret: 'test-secret',
        transport: webhookTransport.transport,
      }),
    );
  });

  // ── Email channel ─────────────────────────────────────────────

  describe('email channel end-to-end', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      // Ensure preferences exist with email enabled (default)
      preferencesService.getOrCreatePreferences('alice@example.com');

      await eventBus.emit(makeOrderCreatedEvent());

      // Adapter received the email
      expect(emailTransport.sent).toHaveLength(1);
      expect(emailTransport.sent[0]!.to).toBe('alice@example.com');
      expect(emailTransport.sent[0]!.subject).toContain('Order Confirmation');
      expect(emailTransport.sent[0]!.from).toBe('noreply@shop.test');

      // Notification recorded as delivered
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.delivered).toBe(true);
      expect(notifications[0]!.channel).toBe('email');
    });

    it('should render email template with HTML and text versions', async () => {
      preferencesService.getOrCreatePreferences('alice@example.com');

      await eventBus.emit(makeOrderCreatedEvent());

      const email = emailTransport.sent[0]!;
      expect(email.html).toContain('<h1>Order Confirmed</h1>');
      expect(email.html).toContain('Widget x2');
      expect(email.text).toContain('Order Confirmed');
      expect(email.text).toContain('Widget x2');
    });
  });

  // ── SMS channel ───────────────────────────────────────────────

  describe('SMS channel end-to-end', () => {
    it('should deliver SMS notification when SMS preferences are enabled', async () => {
      // Enable SMS for this user (disabled by default)
      preferencesService.updatePreferences('+15559998888', {
        sms: { enabled: true },
      });

      const result = await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15559998888',
        subject: 'Order Confirmed',
        body: 'Your order #123 is confirmed.',
        priority: 'normal',
      });

      expect(result.delivered).toBe(true);
      expect(smsTransport.sent).toHaveLength(1);
      expect(smsTransport.sent[0]!.to).toBe('+15559998888');
      expect(smsTransport.sent[0]!.body).toContain('Order Confirmed');
      expect(smsTransport.sent[0]!.body).toContain('Your order #123 is confirmed.');
    });

    it('should suppress SMS when SMS preferences are disabled (default)', async () => {
      // Create default preferences — SMS is disabled by default
      preferencesService.getOrCreatePreferences('+15559998888');

      const result = await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+15559998888',
        subject: 'Order Confirmed',
        body: 'Your order is confirmed.',
        priority: 'normal',
      });

      expect(result.delivered).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(smsTransport.sent).toHaveLength(0);
    });
  });

  // ── Webhook channel ───────────────────────────────────────────

  describe('webhook channel end-to-end', () => {
    it('should deliver webhook notification', async () => {
      // Webhook enabled by default
      preferencesService.getOrCreatePreferences('system-hook-1');

      const result = await notificationService.sendNotification({
        type: 'order-status-update',
        channel: 'webhook',
        recipient: 'system-hook-1',
        subject: 'Order Shipped',
        body: 'Order #456 has been shipped.',
        priority: 'high',
      });

      expect(result.delivered).toBe(true);
      expect(webhookTransport.sent).toHaveLength(1);

      const request = webhookTransport.sent[0]!;
      expect(request.url).toBe('https://hooks.test/notifications');
      expect(request.headers['X-Webhook-Secret']).toBe('test-secret');
      expect(request.headers['Content-Type']).toBe('application/json');
      expect(request.body.type).toBe('order-status-update');
      expect(request.body.subject).toBe('Order Shipped');
      expect(request.body.recipient).toBe('system-hook-1');
    });

    it('should suppress webhook when webhook preferences are disabled', async () => {
      preferencesService.updatePreferences('system-hook-1', {
        webhook: { enabled: false },
      });

      const result = await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'system-hook-1',
        subject: 'Test',
        body: 'Test body',
        priority: 'normal',
      });

      expect(result.delivered).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(webhookTransport.sent).toHaveLength(0);
    });
  });

  // ── History logging ───────────────────────────────────────────

  describe('notification history logging', () => {
    it('should log delivered notifications to history', async () => {
      preferencesService.getOrCreatePreferences('alice@example.com');

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.queryHistory({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[0]!.subject).toContain('Order Confirmation');
    });

    it('should log suppressed notifications to history', async () => {
      // Disable email
      preferencesService.updatePreferences('alice@example.com', {
        email: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.queryHistory({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('suppressed');
      expect(logs[0]!.error).toBe('Suppressed by user preferences');
    });

    it('should log failed notifications to history', async () => {
      // Register a failing email adapter
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw new Error('SMTP connection refused');
        },
      };
      notificationService.registerAdapter(
        new EmailAdapter({
          from: 'noreply@shop.test',
          transport: failingTransport,
        }),
      );

      preferencesService.getOrCreatePreferences('alice@example.com');
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.queryHistory({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('failed');
      expect(logs[0]!.error).toContain('SMTP connection refused');
    });

    it('should log notifications across all channels', async () => {
      const userId = 'multi-channel-user';

      // Enable all channels
      preferencesService.updatePreferences(userId, {
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      // Send one notification per channel
      await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'email',
        recipient: userId,
        subject: 'Email Test',
        body: 'Email body',
        priority: 'normal',
      });
      await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: userId,
        subject: 'SMS Test',
        body: 'SMS body',
        priority: 'normal',
      });
      await notificationService.sendNotification({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: userId,
        subject: 'Webhook Test',
        body: 'Webhook body',
        priority: 'normal',
      });

      const logs = historyService.queryHistory({ recipient: userId });
      expect(logs).toHaveLength(3);

      const channels = logs.map((l) => l.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);

      // All should be delivered
      expect(logs.every((l) => l.status === 'delivered')).toBe(true);
      expect(historyService.getLogCount()).toBe(3);
    });
  });

  // ── Preferences enforcement ───────────────────────────────────

  describe('preferences enforcement', () => {
    it('should send notification when no preferences exist (backward compat)', async () => {
      // Do NOT create preferences for alice — should default to sending
      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailTransport.sent).toHaveLength(1);
      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.delivered).toBe(true);
    });

    it('should suppress notification when email channel is disabled', async () => {
      preferencesService.updatePreferences('alice@example.com', {
        email: { enabled: false },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailTransport.sent).toHaveLength(0);
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.delivered).toBe(false);
      expect(notifications[0]!.error).toBe('Suppressed by user preferences');
    });

    it('should suppress notification when category is unsubscribed', async () => {
      preferencesService.updatePreferences('alice@example.com', {
        email: {
          enabled: true,
          subscribedCategories: ['order-status-update', 'welcome', 'account-updated'],
          // NOT subscribed to 'order-confirmation'
        },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailTransport.sent).toHaveLength(0);
      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.delivered).toBe(false);
    });

    it('should allow notification when user is subscribed to category', async () => {
      preferencesService.updatePreferences('alice@example.com', {
        email: {
          enabled: true,
          subscribedCategories: ['order-confirmation'],
        },
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(emailTransport.sent).toHaveLength(1);
      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.delivered).toBe(true);
    });

    it('should enforce per-channel preferences independently', async () => {
      const userId = 'channel-test-user';

      // Email enabled, SMS disabled, webhook enabled
      preferencesService.updatePreferences(userId, {
        email: { enabled: true },
        sms: { enabled: false },
        webhook: { enabled: true },
      });

      const emailResult = await notificationService.sendNotification({
        type: 'welcome',
        channel: 'email',
        recipient: userId,
        subject: 'Welcome',
        body: 'Welcome!',
        priority: 'normal',
      });
      const smsResult = await notificationService.sendNotification({
        type: 'welcome',
        channel: 'sms',
        recipient: userId,
        subject: 'Welcome',
        body: 'Welcome!',
        priority: 'normal',
      });
      const webhookResult = await notificationService.sendNotification({
        type: 'welcome',
        channel: 'webhook',
        recipient: userId,
        subject: 'Welcome',
        body: 'Welcome!',
        priority: 'normal',
      });

      expect(emailResult.delivered).toBe(true);
      expect(smsResult.delivered).toBe(false);
      expect(smsResult.error).toBe('Suppressed by user preferences');
      expect(webhookResult.delivered).toBe(true);

      // Verify transports
      expect(emailTransport.sent).toHaveLength(1);
      expect(smsTransport.sent).toHaveLength(0);
      expect(webhookTransport.sent).toHaveLength(1);
    });

    it('should respect updated preferences for subsequent notifications', async () => {
      const userId = 'alice@example.com';

      // Start with email enabled
      preferencesService.getOrCreatePreferences(userId);

      await eventBus.emit(makeOrderCreatedEvent());
      expect(emailTransport.sent).toHaveLength(1);

      // Disable email
      preferencesService.updatePreferences(userId, { email: { enabled: false } });

      await eventBus.emit(makeOrderCreatedEvent());
      expect(emailTransport.sent).toHaveLength(1); // still 1, second was suppressed

      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]!.delivered).toBe(true);
      expect(notifications[1]!.delivered).toBe(false);
    });
