  // ── Notification ordering ─────────────────────────────────────

  describe('notification ordering', () => {
    it('should preserve delivery order with variable adapter latency', async () => {
      const deliveryOrder: string[] = [];
      let callCount = 0;

      // Replace email adapter with one that has variable latency
      const slowThenFastAdapter = {
        channel: 'email' as const,
        async send(payload: { id: string; type: string; [k: string]: unknown }) {
          callCount++;
          const delay = callCount === 1 ? 50 : 5;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.type);
          return {
            success: true,
            notificationId: payload.id,
            channel: 'email' as const,
            deliveredAt: new Date(),
          };
        },
      };

      notificationService.registerAdapter(slowThenFastAdapter);

      // Emit two events concurrently
      await Promise.all([
        eventBus.emit(makeOrderCreatedEvent()),
        eventBus.emit(makeStatusChangedEvent()),
      ]);

      // Should be in emission order, not completion order
      expect(deliveryOrder).toEqual(['order-confirmation', 'order-status-update']);
    });

    it('should record notifications in order in history', async () => {
      preferencesService.getOrCreatePreferences('alice@example.com');

      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const logs = historyService.queryHistory({ recipient: 'alice@example.com' });
      expect(logs).toHaveLength(2);
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[1]!.type).toBe('order-status-update');

      // IDs should be sequential
      const notifications = notificationService.getNotifications();
      expect(notifications[0]!.id).toBe('notif-0001');
      expect(notifications[1]!.id).toBe('notif-0002');
    });

    it('should maintain order across mixed channels', async () => {
      const userId = 'ordering-user';
      preferencesService.updatePreferences(userId, {
        email: { enabled: true },
        sms: { enabled: true },
        webhook: { enabled: true },
