        type: 'order-confirmation',
        channel: 'email',
        recipient: userId,
        subject: 'First',
        body: 'First notification',
        priority: 'normal',
      });
      await notificationService.sendNotification({
        type: 'order-status-update',
        channel: 'sms',
        recipient: userId,
        subject: 'Second',
        body: 'Second notification',
        priority: 'normal',
      });
      await notificationService.sendNotification({
        type: 'welcome',
        channel: 'webhook',
        recipient: userId,
        subject: 'Third',
        body: 'Third notification',
        priority: 'normal',
