      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(3);
      expect(notifications[0]!.subject).toBe('First');
      expect(notifications[1]!.subject).toBe('Second');
      expect(notifications[2]!.subject).toBe('Third');

      const logs = historyService.queryHistory({ recipient: userId });
      expect(logs).toHaveLength(3);
      expect(logs[0]!.subject).toBe('First');
      expect(logs[1]!.subject).toBe('Second');
      expect(logs[2]!.subject).toBe('Third');
    });
