  // ── Full pipeline scenarios ───────────────────────────────────

  describe('full pipeline scenarios', () => {
    it('should handle order lifecycle: created → status changed → history query', async () => {
      preferencesService.getOrCreatePreferences('alice@example.com');

      // Order created
      await eventBus.emit(makeOrderCreatedEvent());

      // Order status changed
      await eventBus.emit(makeStatusChangedEvent());

      // Verify emails sent
      expect(emailTransport.sent).toHaveLength(2);
      expect(emailTransport.sent[0]!.subject).toContain('Order Confirmation');
      expect(emailTransport.sent[1]!.subject).toContain('Order Update');

      // Verify history
      const allLogs = historyService.queryHistory({});
      expect(allLogs).toHaveLength(2);
      expect(allLogs.every((l) => l.status === 'delivered')).toBe(true);

      // Query by type
      const confirmations = historyService.queryHistory({ type: 'order-confirmation' });
      expect(confirmations).toHaveLength(1);

      const updates = historyService.queryHistory({ type: 'order-status-update' });
      expect(updates).toHaveLength(1);
    });

    it('should handle mixed delivered and suppressed notifications in history', async () => {
      // Alice gets emails, Bob has email disabled
      preferencesService.getOrCreatePreferences('alice@example.com');
      preferencesService.updatePreferences('bob@example.com', {
        email: { enabled: false },
      });

      // Send to Alice
      await notificationService.sendNotification({
        type: 'welcome',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Welcome Alice',
        body: 'Welcome!',
        priority: 'normal',
      });

      // Send to Bob (should be suppressed)
      await notificationService.sendNotification({
        type: 'welcome',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Welcome Bob',
        body: 'Welcome!',
        priority: 'normal',
      });

      // Only Alice's email was actually sent
      expect(emailTransport.sent).toHaveLength(1);
      expect(emailTransport.sent[0]!.to).toBe('alice@example.com');

      // Both are in history
      const allLogs = historyService.queryHistory({});
      expect(allLogs).toHaveLength(2);

